import os
import json
import hashlib
import sqlite3
from flask import Flask, request, jsonify, abort
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from werkzeug.utils import secure_filename
from PIL import Image
import numpy as np
from collections import Counter
import logging
from datetime import datetime
import uuid

app = Flask(__name__)
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your-secret-key-here')

# Ensure upload directory exists
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

# Rate limiting
limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["200 per hour"]
)

# Setup logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Database setup
def init_db():
    conn = sqlite3.connect('annotations.db')
    c = conn.cursor()
    c.execute('''
        CREATE TABLE IF NOT EXISTS images (
            id TEXT PRIMARY KEY,
            filename TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    c.execute('''
        CREATE TABLE IF NOT EXISTS annotations (
            id TEXT PRIMARY KEY,
            image_id TEXT,
            annotator_id TEXT,
            label TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (image_id) REFERENCES images (id)
        )
    ''')
    conn.commit()
    conn.close()

# Secure file upload
def allowed_file(filename):
    ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

# Hash function for secure identifiers
def generate_hash(data):
    return hashlib.sha256(data.encode()).hexdigest()

# Get image labels with majority voting
def get_majority_vote_labels(image_id):
    conn = sqlite3.connect('annotations.db')
    c = conn.cursor()
    c.execute('''
        SELECT label, COUNT(*) as count 
        FROM annotations 
        WHERE image_id = ? 
        GROUP BY label 
        ORDER BY count DESC
    ''', (image_id,))
    results = c.fetchall()
    conn.close()
    
    if not results:
        return None
    
    # Return label with highest count
    return results[0][0]

# API Routes
@app.route('/upload', methods=['POST'])
@limiter.limit("10 per minute")
def upload_image():
    if 'image' not in request.files:
        abort(400)
    
    file = request.files['image']
    if file.filename == '':
        abort(400)
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        unique_id = str(uuid.uuid4())
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_id + '_' + filename)
        file.save(filepath)
        
        # Store in database
        conn = sqlite3.connect('annotations.db')
        c = conn.cursor()
        c.execute('INSERT INTO images (id, filename) VALUES (?, ?)', 
                 (unique_id, filename))
        conn.commit()
        conn.close()
        
        logger.info(f"Uploaded image {unique_id}")
        return jsonify({'image_id': unique_id, 'filename': filename})
    
    abort(400)

@app.route('/label/<image_id>', methods=['POST'])
@limiter.limit("50 per minute")
def add_label(image_id):
    data = request.get_json()
    if not data or 'label' not in data:
        abort(400)
    
    label = data['label']
    annotator_id = request.headers.get('X-Annotator-ID', 'unknown')
    
    # Validate label (basic validation)
    if not isinstance(label, str) or len(label.strip()) == 0:
        abort(400)
    
    # Store annotation
    annotation_id = generate_hash(f"{image_id}_{annotator_id}_{label}")
    
    conn = sqlite3.connect('annotations.db')
    c = conn.cursor()
    try:
        c.execute('INSERT INTO annotations (id, image_id, annotator_id, label) VALUES (?, ?, ?, ?)', 
                 (annotation_id, image_id, annotator_id, label))
        conn.commit()
        logger.info(f"Added label {label} for image {image_id}")
    except sqlite3.IntegrityError:
        conn.rollback()
        abort(409)
    finally:
        conn.close()
    
    return jsonify({'status': 'success', 'annotation_id': annotation_id})

@app.route('/labels/<image_id>', methods=['GET'])
def get_labels(image_id):
    label = get_majority_vote_labels(image_id)
    if label is None:
        return jsonify({'error': 'No labels found'}), 404
    
    return jsonify({'image_id': image_id, 'majority_label': label})

@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'})

# Initialize database on startup
init_db()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)